  1	import * as React from 'react';
  2	import { cephStorageLabel } from '@odf/core/constants';
  3	import { useNodesData } from '@odf/core/hooks';
  4	import { NodeData } from '@odf/core/types';
  5	import {
  6	  getZone,
  7	  nodesWithoutTaints,
  8	  getNodeCPUCapacity,
  9	  getNodeTotalMemory,
 10	} from '@odf/core/utils';
 11	import { StatusBox } from '@odf/shared/generic/status-box';
 12	import { NodeModel } from '@odf/shared/models';
 13	import ResourceLink from '@odf/shared/resource-link/resource-link';
 14	import { getName, hasLabel } from '@odf/shared/selectors';
 15	import {
 16	  SelectableTable,
 17	  TableVariant,
 18	  RowComponentType,
 19	  TableColumnProps,
 20	} from '@odf/shared/table';
 21	import { NodeKind } from '@odf/shared/types';
 22	import { useCustomTranslation } from '@odf/shared/useCustomTranslationHook';
 23	import {
 24	  resourcePathFromModel,
 25	  getConvertedUnits,
 26	  getNodeRoles,
 27	  humanizeCpuCores,
 28	} from '@odf/shared/utils';
 29	import {
 30	  ListPageBody,
 31	  ListPageFilter,
 32	  useListPageFilter,
 33	} from '@openshift-console/dynamic-plugin-sdk';
 34	import classNames from 'classnames';
 35	import * as _ from 'lodash-es';
 36	import { Td } from '@patternfly/react-table';
 37	import { SortByDirection } from '@patternfly/react-table';
 38	import { WizardNodeState, WizardState } from '../reducer';
 39	import { SelectNodesTableFooter } from './select-nodes-table-footer';
 40	import './select-nodes-table.scss';
 41	
 42	const tableColumnClasses = {
 43	  name: classNames('pf-v6-u-w-33-on-md', 'pf-v6-u-w-50-on-sm'),
 44	  role: classNames(
 45	    'pf-m-hidden',
 46	    'pf-m-visible-on-xl',
 47	    'pf-v6-u-w-inherit-on-xl'
 48	  ),
 49	  cpu: classNames(
 50	    'pf-m-hidden',
 51	    'pf-m-visible-on-xl',
 52	    'pf-v6-u-w-inherit-on-xl'
 53	  ),
 54	  memory: classNames(
 55	    'pf-m-hidden',
 56	    'pf-m-visible-on-xl',
 57	    'pf-v6-u-w-inherit-on-xl'
 58	  ),
 59	  zone: classNames('pf-v6-u-w-inherit'),
 60	};
 61	
 62	const NodeRow: React.FC<RowComponentType<NodeData>> = ({ row: node }) => {
 63	  const { t } = useCustomTranslation();
 64	  const roles = getNodeRoles(node).sort();
 65	  const cpuSpec: string = getNodeCPUCapacity(node);
 66	  const memSpec: string = getNodeTotalMemory(node);
 67	
 68	  return (
 69	    <>
 70	      <Td dataLabel={t('Name')}>
 71	        <ResourceLink
 72	          link={resourcePathFromModel(NodeModel, getName(node))}
 73	          resourceModel={NodeModel}
 74	          resourceName={getName(node)}
 75	        />
 76	      </Td>
 77	      <Td dataLabel={t('Role')}>{roles.join(', ') ?? '-'}</Td>
 78	      <Td dataLabel={t('CPU')}>{humanizeCpuCores(cpuSpec).string || '-'}</Td>
 79	      <Td dataLabel={t('Memory')}>{getConvertedUnits(memSpec)}</Td>
 80	      <Td dataLabel={t('Zone')}>{getZone(node) || '-'}</Td>
 81	    </>
 82	  );
 83	};
 84	
 85	const nameSort = (a: NodeData, b: NodeData, direction: SortByDirection) => {
 86	  const negation = direction !== 'asc';
 87	  const sortVal = a?.metadata.name.localeCompare(b?.metadata.name);
 88	  return negation ? -sortVal : sortVal;
 89	};
 90	
 91	const InternalNodeTable: React.FC<NodeTableProps> = ({
 92	  onRowSelected,
 93	  nodesData,
 94	  disableLabeledNodes,
 95	  systemNamespace,
 96	}) => {
 97	  const { t } = useCustomTranslation();
 98	  const storageLabel = cephStorageLabel(systemNamespace);
 99	
100	  const getColumns = React.useMemo(
101	    (): TableColumnProps[] => [
102	      {
103	        columnName: t('Name'),
104	        sortFunction: nameSort as <T>(a: T, b: T, c: SortByDirection) => number,
105	        thProps: { className: tableColumnClasses.name },
106	      },
107	      {
108	        columnName: t('Role'),
109	        thProps: { className: tableColumnClasses.role },
110	      },
111	      {
112	        columnName: t('CPU'),
113	        thProps: { className: tableColumnClasses.cpu },
114	      },
115	      {
116	        columnName: t('Memory'),
117	        thProps: { className: tableColumnClasses.memory },
118	      },
119	      {
120	        columnName: t('Zone'),
121	        thProps: { className: tableColumnClasses.zone },
122	      },
123	    ],
124	    [t]
125	  );
126	
127	  const filteredData = React.useMemo(
128	    () => nodesWithoutTaints(nodesData),
129	    [nodesData]
130	  );
131	
132	  // Initialize with labeled nodes selected
133	  const [selectedNodes, setSelectedNodes] = React.useState<NodeData[]>([]);
134	
135	  React.useEffect(() => {
136	    if (filteredData.length && !selectedNodes.length) {
137	      const preSelected = filteredData.filter((node) =>
138	        hasLabel(node, storageLabel)
139	      );
140	      if (preSelected.length) {
141	        setSelectedNodes(preSelected);
142	        onRowSelected(preSelected);
143	      }
144	    }
145	  }, [filteredData, selectedNodes.length, storageLabel, onRowSelected]);
146	
147	  const handleRowSelection = React.useCallback(
148	    (selected: NodeData[]) => {
149	      setSelectedNodes(selected);
150	      onRowSelected(selected);
151	    },
152	    [onRowSelected]
153	  );
154	
155	  const isRowSelectable = React.useCallback(
156	    (node: NodeData) => {
157	      // If disableLabeledNodes is true, nodes with storage label cannot be deselected
158	      if (disableLabeledNodes && hasLabel(node as NodeKind, storageLabel)) {
159	        return false;
160	      }
161	      return true;
162	    },
163	    [disableLabeledNodes, storageLabel]
164	  ) as (row: any) => boolean;
165	
166	  return (
167	    <div className="ceph-odf-install__select-nodes-table">
168	      <SelectableTable<NodeData>
169	        columns={getColumns}
170	        rows={filteredData}
171	        RowComponent={NodeRow}
172	        selectedRows={selectedNodes}
173	        setSelectedRows={handleRowSelection}
174	        loaded={true}
175	        variant={TableVariant.COMPACT}
176	        initialSortColumnIndex={0}
177	        isRowSelectable={isRowSelectable}
178	        isColumnSelectableHidden={disableLabeledNodes}
179	      />
180	    </div>
181	  );
182	};
183	
184	type NodeTableProps = {
185	  onRowSelected: (selectedNodes: NodeKind[]) => void;
186	  nodesData: NodeData[];
187	  disableLabeledNodes: boolean;
188	  systemNamespace: WizardState['backingStorage']['systemNamespace'];
189	};
190	
191	export const SelectNodesTable: React.FC<SelectNodesTableProps> = ({
192	  nodes,
193	  onRowSelected,
194	  disableLabeledNodes = false,
195	  systemNamespace,
196	}) => {
197	  const [nodesData, nodesLoaded, nodesLoadError] = useNodesData();
198	  const [data, filteredData, onFilterChange] = useListPageFilter(nodesData);
199	
200	  return (
201	    <div className="odf-capacity-and-nodes__select-nodes">
202	      <ListPageBody>
203	        <ListPageFilter
204	          data={data}
205	          loaded={nodesLoaded}
206	          onFilterChange={onFilterChange}
207	          hideColumnManagement={true}
208	        />
209	        <StatusBox
210	          skeleton={<div className="loading-skeleton--table" />}
211	          data={filteredData}
212	          loaded={nodesLoaded}
213	          loadError={nodesLoadError}
214	        >
215	          <InternalNodeTable
216	            onRowSelected={onRowSelected}
217	            nodesData={filteredData}
218	            disableLabeledNodes={disableLabeledNodes}
219	            systemNamespace={systemNamespace}
220	          />
221	        </StatusBox>
222	      </ListPageBody>
223	      {!!nodes.length && <SelectNodesTableFooter nodes={nodes} />}
224	    </div>
225	  );
226	};
227	
228	type SelectNodesTableProps = {
229	  nodes: WizardNodeState[];
230	  onRowSelected: (selectedNodes: NodeData[]) => void;
231	  disableLabeledNodes?: boolean;
232	  systemNamespace: WizardState['backingStorage']['systemNamespace'];
233	};

